1	// Export / import is the migration path from the old vanilla-JS app.
2	// Schema MUST match the old exporter exactly: { log: { [key]: entry }, state: { globalDay, currentPhase } }
3	// where key is `${globalDay}_${exerciseIndex}` and entry is the LogEntry shape from types.ts.
4	// This is the only contract the legacy app and the new app share — don't change it.
5	
6	import {
7	  loadLog,
8	  loadState,
9	  putLogEntry,
10	  saveState,
11	  sanitizeLogEntry,
12	} from '../state';
13	import type { ExportPayload, LogEntry, LogMap, WorkoutState } from '../types';
14	
15	export async function exportPayload(): Promise<ExportPayload> {
16	  const log = await loadLog();
17	  const state = await loadState();
18	  return { log, state };
19	}
20	
21	export function downloadExport(payload: ExportPayload, filename?: string): void {
22	  const today = new Date().toISOString().slice(0, 10);
23	  const name = filename ?? `flux-backup-${today}.json`;
24	  const blob = new Blob([JSON.stringify(payload, null, 2)], {
25	    type: 'application/json',
26	  });
27	  const url = URL.createObjectURL(blob);
28	  const a = document.createElement('a');
29	  a.href = url;
30	  a.download = name;
31	  document.body.appendChild(a);
32	  a.click();
33	  document.body.removeChild(a);
34	  URL.revokeObjectURL(url);
35	}
36	
37	export interface ImportResult {
38	  imported: number;
39	  skipped: number;
40	  total: number;
41	  stateApplied: boolean;
42	}
43	
44	// Apply an export payload to the current IDB. Sanitizes every entry, merges
45	// (skips keys that already exist), and optionally restores state. Throws on
46	// payloads that don't match the legacy schema so the UI can surface an error.
47	export async function applyImport(
48	  raw: unknown,
49	  opts: { applyState?: boolean } = {},
50	): Promise<ImportResult> {
51	  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
52	    throw new Error('Invalid backup: not an object');
53	  }
54	  const data = raw as Record<string, unknown>;
55	  if (!data.log || typeof data.log !== 'object' || Array.isArray(data.log)) {
56	    throw new Error('Invalid backup: missing or malformed log');
57	  }
58	
59	  const incoming = data.log as Record<string, unknown>;
60	  const keys = Object.keys(incoming);
61	  const existing = await loadLog();
62	
63	  let imported = 0;
64	  let skipped = 0;
65	  for (const key of keys) {
66	    if (existing[key]) {
67	      skipped++;
68	      continue;
69	    }
70	    const sanitized = sanitizeLogEntry(incoming[key]);
71	    if (!sanitized) {
72	      skipped++;
73	      continue;
