1	// Web Audio beep used at timer completion. Lazily-constructed shared context.
2	let audioCtx: AudioContext | null = null;
3	
4	function getAudioContext(): AudioContext | null {
5	  if (typeof window === 'undefined') return null;
6	  if (!audioCtx) {
7	    const Ctor =
8	      window.AudioContext ??
9	      (window as unknown as { webkitAudioContext?: typeof AudioContext })
10	        .webkitAudioContext;
11	    if (!Ctor) return null;
12	    audioCtx = new Ctor();
13	  }
14	  return audioCtx;
15	}
16	
17	function tone(ctx: AudioContext, freq: number, start: number, duration: number): void {
18	  const osc = ctx.createOscillator();
19	  const gain = ctx.createGain();
20	  osc.type = 'square';
21	  osc.frequency.value = freq;
22	  gain.gain.setValueAtTime(0.15, start);
23	  gain.gain.exponentialRampToValueAtTime(0.01, start + duration);
24	  osc.connect(gain);
25	  gain.connect(ctx.destination);
26	  osc.start(start);
27	  osc.stop(start + duration);
28	}
29	
30	export function playBeep(): void {
31	  try {
32	    const ctx = getAudioContext();
33	    if (!ctx) return;
34	    const now = ctx.currentTime;
35	    tone(ctx, 880, now, 0.15);
36	    tone(ctx, 660, now + 0.15, 0.2);
37	  } catch {
38	    // audio unavailable — fail silently
39	  }
