// Exercise catalog types. The catalog is the vocabulary of every exercise
// Flux supports — its entries hold the metadata that is intrinsic to an
// exercise (what muscles it works, what equipment it needs, how to perform
// it safely). This is source-of-truth data that ships with the app.
//
// A Workout Program (see src/tabs/Workouts/types.ts) is a separate concept:
// it's runtime user data that references catalog entries by `id` and adds
// program-specific fields like sets, reps, and weight.

export interface Exercise {
  id: string;
  name: string;
  muscleGroups?: string[];
  equipment?: string[];
  demoVideoId?: string;
  demoVideoStart?: number;
  technique?: string;
  safety?: string;
}

export type ExerciseCatalog = Record<string, Exercise>;

