1	import { openDb, dbGet, dbPut, dbPutMany, dbDelete, dbClear, dbGetAll } from '../../db/idb';
2	import type { LogEntry, LogMap, WorkoutState } from './types';
3	
4	const DB_NAME = 'flux-db';
5	const DB_VERSION = 1;
6	const STATE_STORE = 'state';
7	const LOG_STORE = 'log';
8	const STATE_KEY = 'current';
9	
10	const DIFFICULTIES = new Set(['easy', 'good', 'hard', 'failed']);
11	
12	let dbPromise: Promise<IDBDatabase> | null = null;
13	
14	export function getDb(): Promise<IDBDatabase> {
15	  if (!dbPromise) {
16	    dbPromise = openDb({
17	      name: DB_NAME,
18	      version: DB_VERSION,
19	      stores: [{ name: STATE_STORE }, { name: LOG_STORE }],
20	    });
21	  }
22	  return dbPromise;
23	}
24	
25	export const DEFAULT_STATE: WorkoutState = { globalDay: 1, currentPhase: 'p1' };
26	
27	export async function loadState(): Promise<WorkoutState> {
28	  const db = await getDb();
29	  const saved = await dbGet<WorkoutState>(db, STATE_STORE, STATE_KEY);
30	  if (!saved) return { ...DEFAULT_STATE };
31	  const day = Number(saved.globalDay);
32	  return {
33	    globalDay: Number.isInteger(day) && day >= 1 ? day : 1,
34	    currentPhase:
35	      typeof saved.currentPhase === 'string' ? saved.currentPhase : 'p1',
36	  };
37	}
38	
39	export async function saveState(state: WorkoutState): Promise<void> {
40	  const db = await getDb();
41	  await dbPut(db, STATE_STORE, state, STATE_KEY);
42	}
43	
44	export async function loadLog(): Promise<LogMap> {
45	  const db = await getDb();
46	  const tx = db.transaction(LOG_STORE, 'readonly');
47	  const store = tx.objectStore(LOG_STORE);
48	  return new Promise((resolve, reject) => {
49	    const result: LogMap = {};
50	    const req = store.openCursor();
51	    req.onsuccess = () => {
52	      const cursor = req.result;
53	      if (cursor) {
54	        result[String(cursor.key)] = cursor.value as LogEntry;
55	        cursor.continue();
56	      } else {
57	        resolve(result);
58	      }
59	    };
60	    req.onerror = () => reject(req.error);
61	  });
62	}
63	
64	export async function putLogEntry(key: string, entry: LogEntry): Promise<void> {
65	  const db = await getDb();
66	  await dbPut(db, LOG_STORE, entry, key);
67	}
68	
69	export async function putLogEntries(
70	  entries: Array<{ key: string; entry: LogEntry }>,
71	): Promise<void> {
72	  const db = await getDb();
73	  await dbPutMany(
74	    db,
75	    LOG_STORE,
76	    entries.map(({ key, entry }) => ({ key, value: entry })),
77	  );
78	}
79	
