// A WorkoutExercise references an entry from the exercise catalog by id
// and layers program-specific fields on top: sets, reps, rest, and weight
// progression. The catalog (src/data/exerciseCatalog.ts) is the source of
// truth for name, demo video, and technique notes — those are not stored
// here.
//
// `exercise_name` and `from_legacy_import` are populated by the legacy
// importer when an exercise can't be mapped to a catalog id. The UI shows
// these entries with a small "unmapped" badge but they still log fine.
export interface WorkoutExercise {
  exercise_id: string;
  sets: number;
  reps: string;
  rest: string;
  notes?: string;
  uses_weight: boolean;
  starting_weight?: number;
  weight_increment?: number;
  exercise_name?: string;
  from_legacy_import?: boolean;
}

export interface Workout {
  name: string;
  focus: string;
  exercises: WorkoutExercise[];
}

export interface Phase {
  id: string;
  name: string;
  duration_weeks: number;
  description?: string;
  schedule_pattern?: string[];
  workouts: Record<string, Workout>;
}

export interface ProgramMeta {
  startDate: string;
  version: string;
  principles: string[];
  constraints: {
    mobility_required: boolean;
    min_mobility_days_per_week: number;
  };
}

export interface Program {
  meta: ProgramMeta;
  phases: Phase[];
}

export type Difficulty = 'easy' | 'good' | 'hard' | 'failed';

export interface LogEntry {
  exercise: string;
  weight?: number;
  difficulty?: Difficulty;
  notes?: string;
  completed?: boolean;
  day: number;
  timestamp: number;
  failedSet?: number;
  failedRep?: number;
}

export type LogMap = Record<string, LogEntry>;

export interface WorkoutState {
  globalDay: number;
  currentPhase: string;
}

export interface ExportPayload {
  log: LogMap;
  state: Partial<WorkoutState>;
  program?: Program;
}

