// Export / import handles two formats:
//
//   1. New Flux format: { log, state, program } — program references catalog
//      ids on every WorkoutExercise. Direct roundtrip.
//   2. Legacy format: { log, state, program? } — program (if any) references
//      exercises by `name`. Names are mapped to catalog ids with
//      mapExerciseByName; unmapped names are preserved on the WorkoutExercise
//      as `exercise_name` + `from_legacy_import: true` so logging still works.
//
// Format is detected by sniffing the first exercise of the first phase:
// presence of `exercise_id` means new format; otherwise legacy. Pure
// log/state files with no `program` key skip the program path entirely.

import { mapExerciseByName } from '../../../data/exerciseCatalog';
import {
  loadLog,
  loadProgram,
  loadState,
  putLogEntries,
  saveProgram,
  saveState,
  sanitizeLogEntry,
} from '../state';
import type {
  ExportPayload,
  LogEntry,
  LogMap,
  Program,
  WorkoutExercise,
  WorkoutState,
} from '../types';

export async function exportPayload(): Promise<ExportPayload> {
  const log = await loadLog();
  const state = await loadState();
  const program = await loadProgram();
  return program ? { log, state, program } : { log, state };
}

export function downloadExport(payload: ExportPayload, filename?: string): void {
  const today = new Date().toISOString().slice(0, 10);
  const name = filename ?? `flux-backup-${today}.json`;
  const blob = new Blob([JSON.stringify(payload, null, 2)], {
    type: 'application/json',
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = name;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

export interface ImportResult {
  imported: number;
  skipped: number;
  total: number;
  stateApplied: boolean;
  programImported: boolean;
  exercisesMapped: number;
  exercisesTotal: number;
}

function isObject(v: unknown): v is Record<string, unknown> {
  return typeof v === 'object' && v !== null && !Array.isArray(v);
}

function normalizeExercise(
  raw: unknown,
  counters: { total: number; mapped: number },
): WorkoutExercise | null {
  if (!isObject(raw)) return null;
  counters.total += 1;

  const sets = typeof raw.sets === 'number' ? raw.sets : 0;
  const reps = typeof raw.reps === 'string' ? raw.reps : '';
  const rest = typeof raw.rest === 'string' ? raw.rest : '';
  const uses_weight = raw.uses_weight === true;
  const starting_weight =
    typeof raw.starting_weight === 'number' ? raw.starting_weight : undefined;
  const weight_increment =
    typeof raw.weight_increment === 'number' ? raw.weight_increment : undefined;
  const notes = typeof raw.notes === 'string' ? raw.notes : undefined;
  const base = {
    sets,
    reps,
    rest,
    uses_weight,
    ...(starting_weight !== undefined ? { starting_weight } : {}),
    ...(weight_increment !== undefined ? { weight_increment } : {}),
    ...(notes ? { notes } : {}),
  };

  if (typeof raw.exercise_id === 'string' && raw.exercise_id) {
    counters.mapped += 1;
    return { exercise_id: raw.exercise_id, ...base };
  }
  if (typeof raw.name === 'string' && raw.name) {
    const mapped = mapExerciseByName(raw.name);
    if (mapped) {
      counters.mapped += 1;
      return { exercise_id: mapped, ...base };
    }
    return {
      exercise_id: '',
      exercise_name: raw.name,
      from_legacy_import: true,
      ...base,
    };
  }
  return null;
}

function normalizeProgram(
  raw: unknown,
  counters: { total: number; mapped: number },
): Program | null {
  if (!isObject(raw) || !isObject(raw.meta) || !Array.isArray(raw.phases)) {
    return null;
  }
  const meta = raw.meta as Program['meta'];
  const phases: Program['phases'] = [];
  for (const p of raw.phases) {
    if (!isObject(p)) continue;
    const workouts: Program['phases'][number]['workouts'] = {};
    if (isObject(p.workouts)) {
      for (const [k, w] of Object.entries(p.workouts)) {
        if (!isObject(w)) continue;
        const exs = Array.isArray(w.exercises) ? w.exercises : [];
        const mapped: WorkoutExercise[] = [];
        for (const ex of exs) {
          const norm = normalizeExercise(ex, counters);
          if (norm) mapped.push(norm);
        }
        workouts[k] = {
          name: typeof w.name === 'string' ? w.name : '',
          focus: typeof w.focus === 'string' ? w.focus : '',
          exercises: mapped,
        };
      }
    }
    phases.push({
      id: typeof p.id === 'string' ? p.id : '',
      name: typeof p.name === 'string' ? p.name : '',
      duration_weeks: typeof p.duration_weeks === 'number' ? p.duration_weeks : 0,
      ...(typeof p.description === 'string' ? { description: p.description } : {}),
      ...(Array.isArray(p.schedule_pattern)
        ? { schedule_pattern: p.schedule_pattern as string[] }
        : {}),
      workouts,
    });
  }
  return { meta, phases };
}

// Apply an export payload to the current IDB. Sanitizes every entry, merges
// (skips keys that already exist), optionally restores state, and installs
// any program embedded in the payload (with legacy name-mapping if needed).
export async function applyImport(
  raw: unknown,
  opts: { applyState?: boolean } = {},
): Promise<ImportResult> {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
    throw new Error('Invalid backup: not an object');
  }
  const data = raw as Record<string, unknown>;
  if (!data.log || typeof data.log !== 'object' || Array.isArray(data.log)) {
    throw new Error('Invalid backup: missing or malformed log');
  }

  const incoming = data.log as Record<string, unknown>;
  const keys = Object.keys(incoming);
  const existing = await loadLog();

  let imported = 0;
  let skipped = 0;
  const toWrite: Array<{ key: string; entry: LogEntry }> = [];
  for (const key of keys) {
    if (existing[key]) {
      skipped++;
      continue;
    }
    const sanitized = sanitizeLogEntry(incoming[key]);
    if (!sanitized) {
      skipped++;
      continue;
    }
    const entry: LogEntry = {
      exercise: sanitized.exercise ?? '',
      day: sanitized.day ?? 0,
      timestamp: sanitized.timestamp ?? Date.now(),
      ...sanitized,
    };
    toWrite.push({ key, entry });
    imported++;
  }
  await putLogEntries(toWrite);

  let stateApplied = false;
  if (opts.applyState && isObject(data.state)) {
    const s = data.state as Record<string, unknown>;
    const next: WorkoutState = {
      globalDay:
        typeof s.globalDay === 'number' && Number.isInteger(s.globalDay) && s.globalDay >= 1
          ? s.globalDay
          : 1,
      currentPhase: typeof s.currentPhase === 'string' ? s.currentPhase : 'p1',
    };
    await saveState(next);
    stateApplied = true;
  }

  let programImported = false;
  const exerciseCounters = { total: 0, mapped: 0 };
  if (data.program !== undefined) {
    const program = normalizeProgram(data.program, exerciseCounters);
    if (program) {
      await saveProgram(program);
      programImported = true;
    }
  }

  return {
    imported,
    skipped,
    total: keys.length,
    stateApplied,
    programImported,
    exercisesMapped: exerciseCounters.mapped,
    exercisesTotal: exerciseCounters.total,
